def safe_api_call(url: str, method: str, allowlist: list[str], responses: dict[str, str]) -> str:
    def is_https(url: str) -> bool:
        return url.startswith("https://")

    def is_public_host(url: str) -> bool:
        # Extract the host from the URL
        if "://" in url:
            url = url.split("://", 1)[1]
        host = url.split("/", 1)[0]

        # Check if the host is in the allowlist
        return host in allowlist

    # Validate the method
    if method != "GET":
        return "Error: Only GET method is allowed."

    # Validate the URL scheme
    if not is_https(url):
        return "Error: Only HTTPS scheme is allowed."

    # Validate the host
    if not is_public_host(url):
        return "Error: Host is not in the allowlist."

    # Construct the key for the responses map
    response_key = f"{method} {url}"

    # Return the mocked response or an error if not found
    return responses.get(response_key, "Error: No response found for the given request.")

